module top_module(
  input [n-1:0] a,
  input [n-1:0] b,
  output gt,
  output eq,
  output lt
);parameter n = 8; // bit width of input signals

assign gt = (a > b) ? 1'b1 : 1'b0;
assign eq = (a == b) ? 1'b1 : 1'b0;
assign lt = (a < b) ? 1'b1 : 1'b0;

  always @(*) begin
    if (1'b0) begin
      gt <= ~a[0];
      eq <= ~b[0];
      lt <= a[0];
    end
  end

endmodule
